import React, {
  Dispatch,
  SetStateAction,
  useCallback,
  useEffect,
  useMemo,
  useState,
  memo
} from 'react'
import { useDispatch, useSelector } from 'react-redux'
import { CommunityParams, CommunityReply } from 'api/model/platform/communityModel'
import { create, find, update } from 'modules/platform/community'
import {
  Box,
  CircularProgress,
  FormControl,
  FormLabel,
  MenuItem,
  Stack,
  Button,
  TextField,
  Dialog,
  DialogActions,
  DialogContent,
  DialogTitle
} from '@mui/material'
import message from 'components/Message'
import { buttonStyles } from 'components/DeleteModal'

interface FormDialogProps {
  dialogValue?: CommunityReply
  openDialog: boolean
  dialogType: string
  setOpenDialog: Dispatch<SetStateAction<boolean>>
}

const FormDialog: React.FC<FormDialogProps> = ({
  dialogValue,
  openDialog,
  dialogType,
  setOpenDialog
}) => {
  const dispatch = useDispatch<AppDispatch>()
  const { page } = useSelector((state: RootState) => state.CommunitySlice)
  const info = useSelector((state: RootState) => state.info)
  const cityList = useMemo(() => [...info.cityData.list].reverse(), [info.cityData.list])
  const [loading, setLoading] = useState(false)

  const initialFormData = useMemo(() => {
    const commonFields = {
      name: dialogType === 'edit' ? dialogValue?.name || '' : '',
      address: dialogType === 'edit' ? dialogValue?.address || '' : '',
      nearby_landmarks: dialogType === 'edit' ? dialogValue?.nearbyLandmarks || '' : '',
      tel: dialogType === 'edit' ? dialogValue?.tel || '' : '',
      payFeeMonth: dialogType === 'edit' ? dialogValue?.payFeeMonth || 0 : 0,
      feePrice: dialogType === 'edit' ? dialogValue?.feePrice || 0 : 0,
      bId: dialogType === 'edit' ? dialogValue?.bId || '' : '',
      state: dialogType === 'edit' ? dialogValue?.state || '0' : '0'
    }

    const cityCodes =
      dialogType === 'edit' && dialogValue
        ? {
            province_code:
              cityList.find(
                item =>
                  item.areaCode ===
                  cityList.find(items => items.areaCode === dialogValue?.cityCode)?.parentAreaCode
              )?.parentAreaCode || '',
            city_code:
              cityList.find(item => item.areaCode === dialogValue?.cityCode)?.parentAreaCode || '',
            county_code:
              cityList.find(item => item.areaCode === dialogValue?.cityCode)?.areaCode || ''
          }
        : {
            province_code: '',
            city_code: '',
            county_code: ''
          }

    return { ...commonFields, ...cityCodes }
  }, [dialogType, dialogValue, cityList])

  const [formData, setFormData] = useState<CommunityParams>(initialFormData)

  const provinces = useMemo(() => cityList.filter(item => item.areaLevel === '101'), [cityList])

  const cities = useMemo(
    () =>
      formData.province_code
        ? cityList.filter(
            item => item.parentAreaCode === formData.province_code && item.areaLevel === '202'
          )
        : [],
    [formData.province_code, cityList]
  )

  const counties = useMemo(
    () =>
      formData.city_code
        ? cityList.filter(
            item => item.parentAreaCode === formData.city_code && item.areaLevel === '303'
          )
        : [],
    [formData.city_code, cityList]
  )

  useEffect(() => {
    setFormData(initialFormData)
  }, [initialFormData])

  const handleFormChange = (id: string, value: string | number) => {
    setFormData(prev => ({ ...prev, [id]: value }))
  }

  const handleSubmit = useCallback(
    async (event: React.FormEvent<HTMLFormElement>) => {
      event.preventDefault()
      setLoading(true)
      try {
        const params = { ...formData, state: '1000', city_code: formData.county_code }
        const action =
          dialogType === 'add' ? create(params) : update({ id: dialogValue?.id, ...params })
        const res = await dispatch(action)
        if ('error' in res && res.error?.message) {
          throw new Error(res.error.message)
        }
        await dispatch(find({ 'page.num': page.num || '1', 'page.size': page.size }))
        message.success(dialogType === 'add' ? '新建成功' : '编辑成功')
        setOpenDialog(false)
        setFormData(initialFormData)
      } catch (err: unknown) {
        if (err instanceof Error) message.error(err.message)
      } finally {
        setLoading(false)
      }
    },
    [dispatch, dialogType, dialogValue, formData, page, setOpenDialog, initialFormData]
  )

  const formFields = [
    { label: '小区名称', type: 'text', id: 'name', required: true },
    { label: '小区地址', type: 'text', id: 'address', required: true },
    { label: '附近地标', type: 'text', id: 'nearby_landmarks', required: true },
    { label: '客服电话', type: 'text', id: 'tel', required: true },
    { label: '缴费周期', type: 'number', id: 'payFeeMonth', required: true },
    { label: '每月单价', type: 'number', id: 'feePrice', required: true },
    { label: '社区编码', type: 'text', id: 'bId', required: true }
  ]

  return (
    <Dialog
      fullWidth
      maxWidth="sm"
      open={openDialog}
      onClose={() => setOpenDialog(false)}
      slotProps={{ paper: { component: 'form', onSubmit: handleSubmit } }}
    >
      <DialogTitle>{dialogType === 'add' ? '新增' : '编辑'}</DialogTitle>
      <DialogContent dividers sx={{ margin: '0 10px 0' }}>
        <Stack spacing={3}>
          {formFields.map(({ label, type, id, required }) => (
            <Box
              sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}
              key={id}
            >
              <FormLabel>{label}：</FormLabel>
              <TextField
                type={type}
                sx={{ width: '80%' }}
                size="small"
                required={required}
                id={id}
                value={formData[id as keyof CommunityParams]}
                onChange={e => handleFormChange(id, e.target.value)}
              />
            </Box>
          ))}
          <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
            <FormLabel>小区地区：</FormLabel>
            <FormControl sx={{ width: '22%' }} variant="outlined">
              <TextField
                select
                size="small"
                label="请选择省"
                value={formData.province_code}
                onChange={e => handleFormChange('province_code', e.target.value)}
                variant="outlined"
              >
                {provinces.map(option => (
                  <MenuItem key={option.areaCode} value={option.areaCode}>
                    {option.areaName}
                  </MenuItem>
                ))}
              </TextField>
            </FormControl>
            <FormControl sx={{ width: '22%' }} variant="outlined">
              <TextField
                select
                size="small"
                label="请选择市"
                value={formData.city_code}
                onChange={e => handleFormChange('city_code', e.target.value)}
                variant="outlined"
              >
                {cities.map(option => (
                  <MenuItem key={option.areaCode} value={option.areaCode}>
                    {option.areaName}
                  </MenuItem>
                ))}
              </TextField>
            </FormControl>
            <FormControl sx={{ width: '22%' }} variant="outlined">
              <TextField
                select
                size="small"
                label="请选择县"
                value={formData.county_code}
                onChange={e => handleFormChange('county_code', e.target.value)}
                variant="outlined"
              >
                {counties.map(option => (
                  <MenuItem key={option.areaCode} value={option.areaCode}>
                    {option.areaName}
                  </MenuItem>
                ))}
              </TextField>
            </FormControl>
          </Box>
        </Stack>
      </DialogContent>
      <DialogActions>
        <Button variant="contained" color="error" onClick={() => setOpenDialog(false)}>
          取消
        </Button>
        <Button
          variant="contained"
          type="submit"
          color="error"
          sx={buttonStyles('#2660ad', '#1d428a')}
          disabled={loading}
          startIcon={loading && <CircularProgress size={24} color="inherit" />}
        >
          {loading ? '保存中...' : '保存'}
        </Button>
      </DialogActions>
    </Dialog>
  )
}

export default memo(FormDialog)
